import { describe, it, expect, vi, beforeEach } from 'vitest'

// 由于 request.ts 在模块顶层创建 axios 实例并附加拦截器，
// 且依赖 import.meta.env 和 antd message，此处仅对 401 防抖核心逻辑做独立单元验证。

describe('core/request — 401 防抖机制', () => {
  let authExpiredHandled: boolean

  beforeEach(() => {
    authExpiredHandled = false
  })

  /**
   * 模拟 request.ts 中的 401 处理逻辑的防抖状态机
   */
  function handle401(onClearAuth: () => void): boolean {
    if (!authExpiredHandled) {
      authExpiredHandled = true
      onClearAuth()
      setTimeout(() => {
        authExpiredHandled = false
      }, 1000)
      return true
    }
    return false
  }

  it('首次 401 触发 clearAuth', () => {
    const clearAuthFn = vi.fn()
    const called = handle401(clearAuthFn)
    expect(called).toBe(true)
    expect(clearAuthFn).toHaveBeenCalledTimes(1)
  })

  it('同一批次第二个 401 被防抖拦截', () => {
    const clearAuthFn = vi.fn()
    handle401(clearAuthFn)
    const called = handle401(clearAuthFn)
    expect(called).toBe(false)
    expect(clearAuthFn).toHaveBeenCalledTimes(1)
  })
})

