// Zod 运行时校验 — 代码准备
// 逐步为核心 API 响应添加 schema，后端字段变更时运行时报错而非静默失败
//
// 使用方式（示例）：
//   import { UserSchema, validateOrThrow } from '@/core/validation'
//   const users = validateOrThrow(z.array(UserSchema), data.items)

import { z } from 'zod'

// ── 基础分页结构 ──
export const PageDataSchema = <T extends z.ZodTypeAny>(itemSchema: T) =>
  z.object({
    items: z.array(itemSchema),
    total: z.number(),
    page: z.number(),
    page_size: z.number(),
  })

// ── 业务 Schema（示例，后续按需扩展） ──
export const UserSchema = z.object({
  id: z.number(),
  openid: z.string(),
  phone: z.string().nullable(),
  is_active: z.boolean(),
})

export const OrderSchema = z.object({
  id: z.number(),
  order_no: z.string(),
  amount: z.number(),
  status: z.string(),
})

// ── 校验辅助函数 ──

/**
 * 用 Zod schema 校验数据。
 * - 开发环境：校验失败时抛出异常（快速发现字段不匹配）
 * - 生产环境：校验失败时记录日志并降级返回原始数据（不阻塞页面）
 */
export function validateOrThrow<T>(schema: z.ZodSchema<T>, data: unknown): T {
  const result = schema.safeParse(data)
  if (!result.success) {
    console.error('[Zod validation error]', result.error.format())
    if (import.meta.env.PROD) {
      return data as T // 生产降级：返回原始数据
    }
    throw new Error(`API response validation failed: ${result.error.message}`)
  }
  return result.data
}
